// Generate realistic mock data for our HVAC parameters
const temperature = parseFloat((22 + Math.random() * 4).toFixed(1)); // 22°C to 26°C
const humidity = parseFloat((45 + Math.random() * 15).toFixed(1));    // 45% to 60%
const voltage = parseFloat((225 + Math.random() * 10).toFixed(1));   // 225V to 235V
const current = parseFloat((3.5 + Math.random() * 2.0).toFixed(1));  // 3.5A to 5.5A

// Simple calculation for Energy (Power = V * A, simplified representation)
const energy = parseFloat(((voltage * current) / 1000).toFixed(2)); 

// Simulate 0 to 12 people in the zone
const occupancy = Math.floor(Math.random() * 13); 

// Bundle it into a single professional JSON telemetry packet
msg.payload = {
    temperature: temperature,
    humidity: humidity,
    voltage: voltage,
    current: current,
    energy: energy,
    occupancy: occupancy
};

return msg;
